tests.test_body:
define <2 x i43> @lshr_shl_eq_amt_multi_use_splat_vec(<2 x i43> %A) {
  %B = lshr <2 x i43> %A, splat (i43 23)
  %C = shl <2 x i43> %B, splat (i43 23)
  %D = mul <2 x i43> %B, %C
  ret <2 x i43> %D
}

define i1 @shl_failed_to_simplify(i8 %a, i1 %cond) {
  %shl = shl i8 %a, 3
  %sel = select i1 %cond, i8 8, i8 32
  %cmp = icmp eq i8 %shl, %sel
  ret i1 %cmp
}

define i1 @test_eq_shl_nuw_lshr(i64 %x, i64 %y) {
  %shl = shl nuw i64 %x, 4
  %lshr = lshr i64 %y, 1
  %cmp = icmp eq i64 %shl, %lshr
  ret i1 %cmp
}

define i1 @test_ult_shl_nuw_lshr(i64 %x, i64 %y) {
  %shl = shl nuw i64 %x, 4
  %lshr = lshr i64 %y, 1
  %cmp = icmp ult i64 %shl, %lshr
  ret i1 %cmp
}

define i1 @test_uge_shl_nuw_lshr(i64 %x, i64 %y) {
  %shl = shl nuw i64 %x, 4
  %lshr = lshr i64 %y, 1
  %cmp = icmp uge i64 %shl, %lshr
  ret i1 %cmp
}
